<template>
    <canvas id="gameoflife" />
    <!--<div class="overlay"></div>-->
</template>

<script>
    export default{
        name: "GameOfLifeCanvas",
        mounted(){
            init();
        },
    }

    var myGameArea;

    function init(){
        myGameArea = new gameArea('gameoflife');
        window.addEventListener('resize', function(){ myGameArea.resizeCanvas(); }, false);

        //Update game area every few seconds
        setInterval(function(){ myGameArea.update(); }, 100);
    }

    function getRandomInt(max) {
        return Math.floor(Math.random() * max);
    }   

    class gameArea{
        constructor(canvasId){
            this.canvas = document.getElementById(canvasId);
            this.ctx = this.canvas.getContext('2d');

            this.grid = [];
            this.gridX = 70;
            this.gridY = 70;

            //Setup
            //----------------
            for(let x = 0; x < this.gridX; ++x){
                this.grid[x] = [this.gridY];
            }

            for(let x = 0; x < this.gridX; ++x){
                for(let y = 0; y < this.gridY; ++y){
                    this.grid[x][y] = false;//(getRandomInt(200) < 10);
                }
            }

            //Gosper Glider gun setup
            this.grid[3][6] = true;
            this.grid[4][6] = true;
            this.grid[3][7] = true;
            this.grid[4][7] = true;

            this.grid[37][4] = true;
            this.grid[38][4] = true;
            this.grid[37][5] = true;
            this.grid[38][5] = true;

            this.grid[27][2] = true;
            this.grid[27][3] = true;
            this.grid[27][7] = true;
            this.grid[27][8] = true;

            this.grid[25][3] = true;
            this.grid[25][7] = true;

            this.grid[24][4] = true;
            this.grid[24][5] = true;
            this.grid[24][6] = true;

            this.grid[23][4] = true;
            this.grid[23][5] = true;
            this.grid[23][6] = true;

            this.grid[20][7] = true;

            this.grid[19][6] = true;
            this.grid[19][7] = true;
            this.grid[19][8] = true;

            this.grid[18][5] = true;
            this.grid[18][9] = true;

            this.grid[17][7] = true;

            this.grid[16][4] = true;
            this.grid[16][10] = true;

            this.grid[15][4] = true;
            this.grid[15][10] = true;

            this.grid[14][5] = true;
            this.grid[14][9] = true;

            this.grid[13][6] = true;
            this.grid[13][7] = true;
            this.grid[13][8] = true;
            //----------------

            this.resizeCanvas();
        }

        update(){
            let newGrid = [];
            for(let x = 0; x < this.gridX; ++x){
                newGrid[x] = [this.gridY];
            }

            for(let x = 0; x < this.gridX; ++x){
                for(let y = 0; y < this.gridY; ++y){
                    let newState = false;
                    let activeNeighbours = this.getNeighbourCount(x, y);
                    
                    if(this.grid[x][y] && (activeNeighbours == 2 || activeNeighbours == 3)) newState = true;
                    else if (!this.grid[x][y] && activeNeighbours == 3) newState = true;
                    else newState = false;

                    newGrid[x][y] = newState;
                }
            }

            for(let x = 0; x < this.gridX; ++x){
                for(let y = 0; y < this.gridY; ++y){
                    this.grid[x][y] = newGrid[x][y];
                }
            }

            this.draw();
        }

        draw(){
            //Clear Canvas
            this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

            //Draw Cells
            const cellWidth = (this.width / this.gridX);
            const cellHeight = (this.height / this.gridY);

            for(let x = 0; x < this.gridX; ++x){
                for(let y = 0; y < this.gridY; ++y){
                    let posX = (x * cellWidth);
                    let posY = (y * cellHeight);
                    let isActive = this.grid[x][y];
                    this.drawCell(cellWidth, cellHeight, posX, posY, isActive);
                }
            }
        }

        drawCell(width, height, x, y, isActive){
            const activeColor = '#d9d9d9';
            const inactivecolor = '#0f0f0f';

            this.ctx.fillStyle = (isActive ? activeColor : inactivecolor);
            this.ctx.fillRect(x, y, width, height);
            //this.ctx.strokeStyle = 'black';
            //this.ctx.strokeRect(x, y, width, height);
        }

        resizeCanvas(){
            this.canvas.width = window.innerWidth;
            this.canvas.height = window.innerHeight;

            this.width = this.canvas.width;
            this.height = this.canvas.height;
            
            this.draw();
        }

        getNeighbourCount(x, y){
            let count = 0;

            if(this.isNeighbourActive(x - 1, y - 1)) count++; //Top Left
            if(this.isNeighbourActive(x, y - 1)) count++; //Top Middle
            if(this.isNeighbourActive(x + 1, y - 1)) count++; //Top Right
            if(this.isNeighbourActive(x - 1, y)) count++; //Left
            if(this.isNeighbourActive(x + 1, y)) count++; //Right
            if(this.isNeighbourActive(x -  1, y + 1)) count++; //Bottom Left
            if(this.isNeighbourActive(x, y + 1)) count++; //Bottom Middle
            if(this.isNeighbourActive(x + 1, y + 1)) count++; //Bottom Right

            return count;
        }

        isNeighbourActive(x, y){
            return (this.isGridSpaceValid(x, y) && this.grid[x][y]);
        }

        isGridSpaceValid(x, y){
            return (x > 0 && x < this.gridX && y > 0 && y < this.gridY);
        }
    }
</script>

<style scoped>
    #gameoflife{
        position: fixed;
        z-index: -1;
        top: 0;
        left: 0;
        margin: 0;
    }

    .overlay{
        position: fixed;
        top: 0;
        left: 0;
        z-index: 0;
        background: rgba(0, 0, 0, 0.5);
        width: 100%;
        height: 100%;
    }
</style>